def strip_punctuation_space(value):
    "Strip excess whitespace prior to punctuation."
    def strip_punctuation(string):
        replacement_list = (
            (' .',  '.'),
            (' :',  ':'),
            ('( ',  '('),
            (' )',  ')'),
        )
        for match, replacement in replacement_list:
            string = string.replace(match, replacement)
        return string
    if value == None:
        return None
    if type(value) == list:
        return [strip_punctuation(v) for v in value]
    return strip_punctuation(value)

def find(name, arg=None):
    """Find process by name or by argument in command line.

    Args:
        name (str): Process name to search for.
        arg (str): Command line argument for a process to search for.

    Returns:
        tea.process.base.IProcess: Process object if found.
    """
    for p in get_processes():
        if p.name.lower().find(name.lower()) != -1:
            if arg is not None:
                for a in p.cmdline or []:
                    if a.lower().find(arg.lower()) != -1:
                        return p
            else:
                return p
    return None

def git_tag_to_semver(git_tag: str) -> SemVer:
    """
    :git_tag: A string representation of a Git tag.

    Searches a Git tag's string representation for a SemVer, and returns that
    as a SemVer object.
    """
    pattern = re.compile(r'[0-9]+\.[0-9]+\.[0-9]+$')
    match = pattern.search(git_tag)
    if match:
        version = match.group(0)
    else:
        raise InvalidTagFormatException('Tag passed contains no SemVer.')

    return SemVer.from_str(version)

